def fmt_date(d):
    if not d: return "—"
    if isinstance(d, (datetime, date)): return d.strftime("%d.%m.%Y")
    try: return datetime.strptime(str(d)[:10], "%Y-%m-%d").strftime("%d.%m.%Y")
    except: return str(d)

def fmt_num(v, dec=3):
    try: return f"{float(v):,.{dec}f}"
    except: return "—"

def safe(v, default="—"):
    if v is None or str(v).strip() == "": return default
    return str(v).strip()

def number_to_words(amount):
    try:
        amt = float(amount); euros = int(amt); cents = round((amt - euros) * 100)
        ones = ["","ONE","TWO","THREE","FOUR","FIVE","SIX","SEVEN","EIGHT","NINE",
                "TEN","ELEVEN","TWELVE","THIRTEEN","FOURTEEN","FIFTEEN","SIXTEEN",
                "SEVENTEEN","EIGHTEEN","NINETEEN"]
        tens = ["","","TWENTY","THIRTY","FORTY","FIFTY","SIXTY","SEVENTY","EIGHTY","NINETY"]
        def two(n): return ones[n] if n < 20 else tens[n//10]+(" "+ones[n%10] if n%10 else "")
        def three(n): return (ones[n//100]+" HUNDRED"+((" "+two(n%100)) if n%100 else "")) if n>=100 else two(n)
        def convert(n):
            if n==0: return "ZERO"
            p=[]
            if n>=1_000_000: p.append(three(n//1_000_000)+" MILLION"); n%=1_000_000
            if n>=1_000: p.append(three(n//1_000)+" THOUSAND"); n%=1_000
            if n>0: p.append(three(n))
            return " ".join(p)
        w = "EURO-"+convert(euros)
        if cents: w += f" & CENTS {two(cents)}"
        return w+" ONLY."
    except: return "—"

