@ci_pdf_bp.route("/api/pdf/invoice/<path:invoice_no>", methods=["GET"])
def generate_commercial_invoice(invoice_no):
    try:
        conn = get_db(); cur = conn.cursor()
        cur.execute("SELECT * FROM commercial_invoices WHERE invoice_no=%s", (invoice_no,))
        inv = row_to_dict(cur, cur.fetchone())
        if not inv:
            return jsonify({"error": "Invoice not found"}), 404
        cur.execute("SELECT * FROM ci_line_items WHERE invoice_no=%s ORDER BY so_number, size_mm, heat_no", (invoice_no,))
        items = rows_to_list(cur)
        cur.execute("SELECT DISTINCT so_number, so_date FROM ci_line_items WHERE invoice_no=%s ORDER BY so_number", (invoice_no,))
        so_list = rows_to_list(cur)
        cur.close(); conn.close()
        return Response(build_html(inv, items, so_list), mimetype="text/html")
    except Exception as e:
        return jsonify({"error": str(e)}), 500


# ── Auto-create invoice from SO and open it ──────────────────────────────────

@ci_pdf_bp.route("/api/pdf/invoice/from-so/<path:so_number>", methods=["GET"])
def invoice_from_so(so_number):
    """
    Called when user clicks Commercial Invoice on an SO.
    1. Check if invoice already exists for this SO in ci_line_items
    2. If yes → open it
    3. If no → auto-create draft invoice from SO data, then open it
    """
    try:
        conn = get_db(); cur = conn.cursor()

        # Check if invoice already exists for this SO
        cur.execute("""
            SELECT DISTINCT invoice_no FROM ci_line_items
            WHERE so_number=%s ORDER BY invoice_no DESC LIMIT 1
        """, (so_number,))
        row = cur.fetchone()

        if row:
            # Invoice exists — just open it
            invoice_no = row[0]
            cur.execute("SELECT * FROM commercial_invoices WHERE invoice_no=%s", (invoice_no,))
            inv = row_to_dict(cur, cur.fetchone())
            cur.execute("SELECT * FROM ci_line_items WHERE invoice_no=%s ORDER BY so_number, size_mm, heat_no", (invoice_no,))
            items = rows_to_list(cur)
            cur.execute("SELECT DISTINCT so_number, so_date FROM ci_line_items WHERE invoice_no=%s ORDER BY so_number", (invoice_no,))
            so_list = rows_to_list(cur)
            cur.close(); conn.close()
            return Response(build_html(inv, items, so_list), mimetype="text/html")

        # No invoice yet — auto-create from SO data
        cur.execute("SELECT * FROM sales_orders WHERE so_number=%s", (so_number,))
        so = row_to_dict(cur, cur.fetchone())
        if not so:
            cur.close(); conn.close()
            return jsonify({"error": f"SO not found: {so_number}"}), 404

        cur.execute("SELECT * FROM so_line_items WHERE so_number=%s ORDER BY line_no", (so_number,))
        so_items = rows_to_list(cur)

        # Generate invoice number: AIMPL/INV/EXP/XXX/YYYY-YY from SO number
        # SO: AIMPL/S.O/EXP/089/2025-26 → INV: AIMPL/INV/EXP/089/2025-26
        invoice_no = so_number.replace("/S.O/", "/INV/").replace("S.O/", "INV/")
        inv_date   = date.today()

        # Insert into commercial_invoices
        cur.execute("""
            INSERT IGNORE INTO commercial_invoices
            (invoice_no, invoice_date, buyer_name, buyer_address,
             terms_of_payment, country_of_destination, status)
            VALUES (%s, %s, %s, %s, %s, %s, 'Draft')
        """, (
            invoice_no,
            inv_date,
            safe(so.get("customer_name"), ""),
            safe(so.get("delivery_address"), ""),
            safe(so.get("payment_terms"), ""),
            "",
        ))

        # Insert line items from so_line_items (without heat numbers yet)
        for item in so_items:
            grade   = safe(item.get("grade"), "")
            size    = item.get("size_mm") or 0
            length  = item.get("length_mm") or 3000
            tol     = safe(item.get("tolerance", "h9"))
            finish  = safe(item.get("finish", "ANN + PEELED +GROUND"))
            qty_t   = float(item.get("qty_tons") or 0)
            qty_kg  = qty_t * 1000
            rate    = float(item.get("price_euro_per_ton") or item.get("rate_per_ton") or 0)
            value   = float(item.get("amount_euro") or item.get("amount") or 0)

            cur.execute("""
                INSERT INTO ci_line_items
                (invoice_no, so_number, so_date, po_no, po_date,
                 grade, size_mm, length_mm, tolerance, finish,
                 qty_kgs, rate_euro, value_euro)
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """, (
                invoice_no,
                so_number,
                so.get("so_date"),
                safe(so.get("po_number"), ""),
                so.get("po_date"),
                grade,
                size,
                str(length) + "-" + str(int(length) + 200),
                tol,
                finish,
                qty_kg,
                rate,
                value,
            ))

        conn.commit()

        # Now fetch and render
        cur.execute("SELECT * FROM commercial_invoices WHERE invoice_no=%s", (invoice_no,))
        inv = row_to_dict(cur, cur.fetchone())
        cur.execute("SELECT * FROM ci_line_items WHERE invoice_no=%s ORDER BY so_number, size_mm", (invoice_no,))
        items = rows_to_list(cur)
        cur.execute("SELECT DISTINCT so_number, so_date FROM ci_line_items WHERE invoice_no=%s ORDER BY so_number", (invoice_no,))
        so_list = rows_to_list(cur)
        cur.close(); conn.close()

        return Response(build_html(inv, items, so_list), mimetype="text/html")

    except Exception as e:
        import traceback
        return jsonify({"error": str(e), "trace": traceback.format_exc()}), 500


# ── Create invoice from Dispatch ─────────────────────────────────────────────

@ci_pdf_bp.route("/api/invoice/create-from-dispatch/<int:dispatch_id>", methods=["POST"])
def create_from_dispatch(dispatch_id):
    """
    Creates commercial invoice from a dispatch record.
    Called from Dispatch page modal form.
    """
    try:
        data = request.get_json() or {}
        conn = get_db(); cur = conn.cursor()

        # 1. Get dispatch header
        cur.execute("SELECT * FROM dispatches WHERE id=%s", (dispatch_id,))
        disp = row_to_dict(cur, cur.fetchone())
        if not disp:
            return jsonify({"error": "Dispatch not found"}), 404

        # 2. Get dispatch batches (heat-level)
        cur.execute("""
            SELECT db.*, b.so_number
            FROM dispatch_batches db
            LEFT JOIN batches b ON b.batch_card_no = db.batch_card_no
            WHERE db.dispatch_id=%s
            ORDER BY db.size_mm, db.heat_no
        """, (dispatch_id,))
        d_batches = rows_to_list(cur)

        # 3. Get SO numbers linked to this dispatch
        so_numbers = list(set(b.get("so_number","") for b in d_batches if b.get("so_number")))

        # 4. Get SO details
        so_data = {}
        for sn in so_numbers:
            cur.execute("SELECT * FROM sales_orders WHERE so_number=%s", (sn,))
            so = row_to_dict(cur, cur.fetchone())
            if so:
                so_data[sn] = so

        # 5. Generate invoice number from form data or dispatch invoice_no
        invoice_no = data.get("invoice_no") or safe(disp.get("invoice_no"), "")
        if not invoice_no:
            return jsonify({"error": "Invoice number required"}), 400

        inv_date = data.get("invoice_date") or date.today().isoformat()

        # 6. Get SO dates for line items
        # Group batches by SO
        so_batches = {}
        for b in d_batches:
            sn = b.get("so_number","") or ""
            if sn not in so_batches:
                so_batches[sn] = []
            so_batches[sn].append(b)

        # 7. Get so_line_items for rate info
        so_rates = {}  # (so_number, grade, size_mm) -> rate
        for sn in so_numbers:
            cur.execute("SELECT * FROM so_line_items WHERE so_number=%s", (sn,))
            lines = rows_to_list(cur)
            for l in lines:
                key = (sn, safe(l.get("grade","")), float(l.get("size_mm") or 0))
                rate = float(l.get("price_euro_per_ton") or l.get("rate_per_ton") or 0)
                so_rates[key] = rate

        # 8. Insert commercial_invoices header
        buyer_name = data.get("buyer_name") or safe(disp.get("customer",""))
        cur.execute("""
            INSERT INTO commercial_invoices
            (invoice_no, invoice_date, buyer_name, buyer_address,
             pre_carriage, place_of_receipt, vessel_flight,
             port_of_loading, port_of_discharge, final_destination,
             country_of_origin, country_of_destination,
             terms_of_payment, marks_no, container_no, seal_no,
             net_weight, gross_weight, bl_no, status)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,'Draft')
            ON DUPLICATE KEY UPDATE
            invoice_date=VALUES(invoice_date),
            vessel_flight=VALUES(vessel_flight),
            container_no=VALUES(container_no),
            seal_no=VALUES(seal_no),
            bl_no=VALUES(bl_no),
            net_weight=VALUES(net_weight),
            gross_weight=VALUES(gross_weight),
            status='Draft'
        """, (
            invoice_no,
            inv_date,
            buyer_name,
            data.get("buyer_address",""),
            data.get("pre_carriage","BY SEA"),
            data.get("place_of_receipt","JNPT., NHAVA SHEVA"),
            safe(disp.get("vessel_name","")) or data.get("vessel",""),
            safe(disp.get("port_loading","")) or data.get("port_loading","NHAVA SHEVA"),
            safe(disp.get("port_discharge","")) or data.get("port_discharge",""),
            safe(disp.get("final_destination","")) or data.get("final_destination",""),
            "INDIA",
            data.get("country_destination",""),
            data.get("payment_terms",""),
            data.get("marks_no",""),
            safe(disp.get("container_no","")) or data.get("container_no",""),
            safe(disp.get("seal_no","")) or data.get("seal_no",""),
            float(disp.get("total_net_wt_kg") or 0),
            float(disp.get("total_gross_wt_kg") or 0),
            safe(disp.get("bl_number","")) or data.get("bl_no",""),
        ))

        # 9. Delete old line items if regenerating
        cur.execute("DELETE FROM ci_line_items WHERE invoice_no=%s", (invoice_no,))

        # 10. Insert ci_line_items from dispatch_batches
        for b in d_batches:
            sn      = b.get("so_number","") or ""
            so      = so_data.get(sn,{})
            grade   = safe(b.get("grade",""))
            size    = float(b.get("size_mm") or 0)
            heat    = safe(b.get("heat_no",""))
            qty_kg  = float(b.get("net_wt_kg") or 0)
            rate    = so_rates.get((sn, grade, size), 0)
            value   = round((qty_kg / 1000) * rate, 2)

            # Get finish/tolerance from so_line_items
            cur.execute("""
                SELECT tolerance, finish, length_mm, po_number, po_date, so_date
                FROM so_line_items li
                JOIN sales_orders s ON s.so_number=li.so_number
                WHERE li.so_number=%s AND li.grade=%s AND li.size_mm=%s
                LIMIT 1
            """, (sn, grade, size))
            li = row_to_dict(cur, cur.fetchone()) or {}

            cur.execute("""
                INSERT INTO ci_line_items
                (invoice_no, so_number, so_date, po_no, po_date,
                 heat_no, grade, size_mm, length_mm, tolerance, finish,
                 qty_kgs, rate_euro, value_euro)
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """, (
                invoice_no, sn,
                li.get("so_date") or so.get("so_date"),
                safe(li.get("po_number","") or so.get("po_number","")),
                li.get("po_date") or so.get("po_date"),
                heat, grade, size,
                safe(li.get("length_mm","3000-3200")),
                safe(li.get("tolerance","h9")),
                safe(li.get("finish","ANN + PEELED +GROUND")),
                qty_kg, rate, value,
            ))

        conn.commit()
        cur.close(); conn.close()

        return jsonify({
            "success": True,
            "invoice_no": invoice_no,
            "pdf_url": f"/api/pdf/invoice/{invoice_no}"
        })

    except Exception as e:
        import traceback
        return jsonify({"error": str(e), "trace": traceback.format_exc()}), 500


@ci_pdf_bp.route("/api/invoice/dispatch-data/<int:dispatch_id>", methods=["GET"])
def get_dispatch_data(dispatch_id):
    """Returns dispatch data to pre-fill the invoice form."""
    try:
        conn = get_db(); cur = conn.cursor()
        cur.execute("SELECT * FROM dispatches WHERE id=%s", (dispatch_id,))
        disp = row_to_dict(cur, cur.fetchone())
        if not disp:
            return jsonify({"error": "Not found"}), 404

        # Get SO numbers
        cur.execute("""
            SELECT DISTINCT b.so_number FROM dispatch_batches db
            LEFT JOIN batches b ON b.batch_card_no=db.batch_card_no
            WHERE db.dispatch_id=%s AND b.so_number IS NOT NULL
        """, (dispatch_id,))
        so_rows = cur.fetchall()
        so_numbers = [r[0] for r in so_rows if r[0]]

        # Get SO details
        so_details = []
        for sn in so_numbers:
            cur.execute("SELECT * FROM sales_orders WHERE so_number=%s", (sn,))
            so = row_to_dict(cur, cur.fetchone())
            if so:
                so_details.append({
                    "so_number": sn,
                    "customer": so.get("customer_name",""),
                    "po_number": so.get("po_number",""),
                    "payment_terms": so.get("payment_terms",""),
                    "incoterm": so.get("incoterm",""),
                })

        cur.close(); conn.close()

        # Suggest invoice number from first SO
        suggested_inv = ""
        if so_numbers:
            suggested_inv = so_numbers[0].replace("/S.O/","/INV/").replace("S.O/","INV/")

        return jsonify({
            "dispatch": {
                "id": dispatch_id,
                "invoice_no": disp.get("invoice_no",""),
                "customer": disp.get("customer",""),
                "vessel": disp.get("vessel_name",""),
                "container_no": disp.get("container_no",""),
                "seal_no": disp.get("seal_no",""),
                "port_loading": disp.get("port_loading",""),
                "port_discharge": disp.get("port_discharge",""),
                "final_destination": disp.get("final_destination",""),
                "bl_no": disp.get("bl_number",""),
                "net_weight": disp.get("total_net_wt_kg",""),
                "gross_weight": disp.get("total_gross_wt_kg",""),
            },
            "so_numbers": so_numbers,
            "so_details": so_details,
            "suggested_invoice_no": suggested_inv,
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500
